142	    /// Attempts to reserve a slot for sending a message.
143	    fn start_send(&self, token: &mut Token) -> bool {
144	        let backoff = Backoff::new();
145	        let mut tail = self.tail.load(Ordering::Relaxed);
146	
147	        loop {
148	            // Check if the channel is disconnected.
149	            if tail & self.mark_bit != 0 {
150	                token.array.slot = ptr::null();
151	                token.array.stamp = 0;
152	                return true;
153	            }
154	
155	            // Deconstruct the tail.
156	            let index = tail & (self.mark_bit - 1);
157	            let lap = tail & !(self.one_lap - 1);
158	
159	            // Inspect the corresponding slot.
160	            debug_assert!(index < self.buffer.len());
161	            let slot = unsafe { self.buffer.get_unchecked(index) };
162	            let stamp = slot.stamp.load(Ordering::Acquire);
163	
164	            // If the tail and the stamp match, we may attempt to push.
165	            if tail == stamp {
166	                let new_tail = if index + 1 < self.cap() {
167	                    // Same lap, incremented index.
168	                    // Set to `{ lap: lap, mark: 0, index: index + 1 }`.
169	                    tail + 1
170	                } else {
171	                    // One lap forward, index wraps around to zero.
172	                    // Set to `{ lap: lap.wrapping_add(1), mark: 0, index: 0 }`.
173	                    lap.wrapping_add(self.one_lap)
174	                };
175	
176	                // Try moving the tail.
177	                match self.tail.compare_exchange_weak(
178	                    tail,
179	                    new_tail,
180	                    Ordering::SeqCst,
181	                    Ordering::Relaxed,
182	                ) {
183	                    Ok(_) => {
184	                        // Prepare the token for the follow-up call to `write`.
185	                        token.array.slot = slot as *const Slot<T> as *const u8;
186	                        token.array.stamp = tail + 1;
187	                        return true;
188	                    }
189	                    Err(t) => {
190	                        tail = t;
191	                        backoff.spin();
192	                    }
193	                }
194	            } else if stamp.wrapping_add(self.one_lap) == tail + 1 {
195	                atomic::fence(Ordering::SeqCst);
196	                let head = self.head.load(Ordering::Relaxed);
197	
198	                // If the head lags one lap behind the tail as well...
199	                if head.wrapping_add(self.one_lap) == tail {
200	                    // ...then the channel is full.
201	                    return false;
202	                }
203	
204	                backoff.spin();
205	                tail = self.tail.load(Ordering::Relaxed);
206	            } else {
207	                // Snooze because we need to wait for the stamp to get updated.
208	                backoff.snooze();
209	                tail = self.tail.load(Ordering::Relaxed);
210	            }
211	        }
212	    }
